import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { routeNamesInventory } from '../../routeNames';
import { ItemSelection } from '../../INVProducts';
import { priceListStrings } from '../config';
import { priceListActions } from '../actions';
import NewPriceListMainHeaderComponent from './NewPriceListMainHeaderComponent';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, MyDialog, MyTable } from '../../utils';


const style = theme => ({
    root: {
        marginTop : 30,
    }
})
class _NewPriceList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            itemDialog : false
        }
        const {dispatch}= props;
        headerActions({
            [headerStrings.headerTitle]  : ""// "NEW PRICE LIST",
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "New", path : routeNamesInventory.priceListNew}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                NewPriceListMainHeaderComponent
            ],
            [mainStageHeaderStrings.buttons] : [
                {value : "Add Items", onClick : ()=>this.setState({itemDialog : true})}
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [priceListStrings.itemPackages] : itemPackages,
            [priceListStrings.stockCategories] : stockCategories,
        } = this.props;
        if(!itemPackages) priceListActions.getItemPackages()(dispatch);
        if(!stockCategories) priceListActions.getStockCategories()(dispatch);
    }
    render() {
        const {classes} = this.props;
        const { itemDialog } = this.state;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Item", "Brand", "Category", "Package Prices"]}
                    dataMap={["name", "brand", "categoryId", "packagePrice"]}
                    />
                <MyDialog open={itemDialog}>
                    <ItemSelection
                        closeDialog={()=>this.setState({itemDialog : false})}/>
                </MyDialog>
            </div>
        );
    }
}


_NewPriceList.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({priceListReducer}) => ({
    [priceListStrings.itemPackages] : priceListReducer[priceListStrings.itemPackages],
    [priceListStrings.stockCategories] : priceListReducer[priceListStrings.stockCategories],
})


export const NewPriceList = connect(mapStateToProps)(withStyles(style)(_NewPriceList));
export {NewPriceList as default}